import React, { useEffect } from 'react';
import { AsyncStorage } from 'react-native';
import { useSelector } from 'react-redux';
import { LogBox } from 'react-native';

const useDebugLogger = () => {
    const state = useSelector((state) => state);

    const logNetworkRequest = (url, method, data, response) => {
        console.debug(`Network Request: ${method} ${url}`, {
            requestData: data,
            responseData: response,
        });
    };

    const logAsyncStorageOperation = async (operation, key, value) => {
        console.debug(`AsyncStorage ${operation}`, {
            key,
            value,
        });
    };

    const logUserAction = (action) => {
        console.debug(`User Action: ${action}`);
    };

    const logStateChange = (newState) => {
        console.debug('State Change:', newState);
    };

    useEffect(() => {
        const unsubscribe = LogBox.ignoreLogs(['Warning: ...']);
        return () => {
            unsubscribe();
        };
    }, []);

    useEffect(() => {
        logStateChange(state);
    }, [state]);

    return {
        logNetworkRequest,
        logAsyncStorageOperation,
        logUserAction,
    };
};

